import {
  BotonTema,
  Footer,
  Header2,
  Github,
} from "../reutilizables/componentes";

import { useState } from "react";

function borrarToken() {
  localStorage.removeItem("token");
  window.history.back();
}

function cambiarContraseña() {
  const [usuario, setUsuario] = useState("");
  const [cNueva, setCNueva] = useState("");
  const [confirmC, setConfirmC] = useState("");
  const [cActual, setCActual] = useState("");
  return (
    <div>
      <BotonTema />
      <div id="container">
        <header id="header1">
          <button id="volver" onClick={borrarToken}>
            Volver
          </button>
        </header>
        <Header2 />
        <section id="content">
          <input type="text" id="usuarios" placeholder="usuario"></input>
          <input type="text" id="cNueva" placeholder="contraseña nueva"></input>
          <input
            type="text"
            id="confirmC"
            placeholder="confirmar contraseña"
          ></input>
          <input
            type="text"
            id="cActual"
            placeholder="codigo de verificación"
          ></input>

          <button id="enviar" className="principales">
            Solicitar codigo
          </button>
          <a href="/inicioSesion">
            <button id="aceptar" className="principales">
              Cambiar contraseña
            </button>
          </a>
          <a href="/" onClick={borrarToken}>
            <button id="cancelar" className="secundarios">
              cancelar
            </button>
          </a>
        </section>
        <Footer />
      </div>
      <Github />
    </div>
  );
}

export default cambiarContraseña;
